#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
//inline void print(long long p){if(p>9)print(p/10);putchar(p%10+'0');}
const int N=5e5+5,M=2e7+5;const long long INF=4e18;
struct SEG{int l,r,siz,mx,mi;long long sum;}t[M];int cnt,a[N],n,m,mx,Rt[N];
void ins(int cur,int loc,int &RT,int l,int r)
{
	t[RT=++cnt]=t[cur];t[RT].siz++;t[RT].sum+=loc;
	if(l==r)return; int mid=(l+r)>>1;
	if(loc<=mid)ins(t[cur].l,loc,t[RT].l,l,mid);
	else ins(t[cur].r,loc,t[RT].r,mid+1,r);
}
long long Query(int x,int y,int des,int l,int r,int f)
{
	int Sz=t[x].siz-t[y].siz;long long Ds=t[x].sum-t[y].sum;
	long long res=Ds-(((des<<1)+(f<<1)+Sz-1)*Sz>>1);
	if(l>=des+f)return res;if(r<=des+f+Sz-1)return -res;
	int mid=(l+r)>>1,Ls=t[t[x].l].siz-t[t[y].l].siz;
	return Query(t[x].l,t[y].l,des,l,mid,f)+Query(t[x].r,t[y].r,des,mid+1,r,f+Ls);
}
signed main()
{
//	freopen("line5.in","r",stdin);
	n=read(),m=read();rep(1,n,i)mx=max(mx,a[i]=read());//printf("%d %d\n",n,m);
	t[0].mx=-(t[0].mi=INF);rep(1,n,i)ins(Rt[i-1],a[i],Rt[i],1,mx);//puts("nmsl");
	rep(1,m,i)
	{
		int l=read(),r=read(),k=read();
		printf("%lld\n",Query(Rt[r],Rt[l-1],k,1,mx,0));
	}
}
